import React from 'react';

export type LabelProps = {
  htmlFor: string;
  className?: string;
  children:
    | string
    | number
    | JSX.Element
    | Array<string | number | JSX.Element>;
};

const Label: React.FC<LabelProps> = ({
  htmlFor,
  className,
  children
}: LabelProps) => {
  return (
    <label htmlFor={htmlFor} className={`block mb-2 ${className}`}>
      <b>{children}</b>
    </label>
  );
};

Label.displayName = 'Label';
Label.defaultProps = {
  className: ''
};

export default Label;
