import React from 'react';

export type TextareaProps = {
  id: string;
  name: string;
  placeholder: string;
  rows?: number;
  value?: string;
  onChange?: (event: React.ChangeEvent<HTMLTextAreaElement>) => void;
  readOnly?: boolean;
  required?: boolean;
};

const Textarea: React.FC<TextareaProps> = ({
  rows = 2,
  id,
  name,
  placeholder,
  value = '',
  onChange = () => {
    return;
  },
  readOnly = false,
  required = false
}: TextareaProps) => {
  return (
    <textarea
      id={id}
      name={name}
      placeholder={placeholder}
      rows={rows}
      value={value}
      onChange={onChange}
      className="w-full px-3 py-2 rounded border border-solid box-border border-gray-300"
      readOnly={readOnly}
      required={required}
    />
  );
};

Textarea.displayName = 'Textarea';
Textarea.defaultProps = {
  rows: 2,
  value: '',
  onChange: () => {
    return;
  },
  readOnly: false,
  required: false
};

export default Textarea;
