import React from 'react';
import Pricing, { Plan } from '../../organisms/Pricing';
import Contact, { SMS } from '../../organisms/Contact';
import FAQ, { Question } from '../../organisms/FAQ';
import Menu, { Section } from '../../organisms/Menu';
import Footer from '../../organisms/Footer';
import { sites } from '../../../data';

export type PricingSection = {
  id: string;
  title: string;
  subtitle: string;
  plans: Array<Plan>;
};

export type FAQSection = {
  id: string;
  title: string;
  subtitle: string;
  questions: Array<Question>;
};

export type ContactSection = {
  id: string;
  title: string;
  address: string;
  email: string;
  sms: Array<SMS>;
};

const ContactTemplate: React.FC<{
  sections: Array<Section>;
  pricing: PricingSection;
  faq: FAQSection;
  contact: ContactSection;
}> = ({ sections, pricing, faq, contact }) => {
  return (
    <>
      <Menu fixed sections={sections} />
      <main className="pt-32">
        <Pricing
          id={pricing.id}
          title={pricing.title}
          subtitle={pricing.subtitle}
          plans={pricing.plans}
        ></Pricing>
        <FAQ
          id={faq.id}
          title={faq.title}
          subtitle={faq.subtitle}
          questions={faq.questions}
        />
        <Contact
          id={contact.id}
          title={contact.title}
          address={contact.address}
          email={contact.email}
          sms={contact.sms}
        />
      </main>
      <Footer sites={sites} />
    </>
  );
};

export default ContactTemplate;
